const input = $input.first().json;
const body = input.body ?? input;
const value = body.entry?.[0]?.changes?.[0]?.value ?? body;
const contact = value.contacts?.[0] ?? {};
const message = value.messages?.[0] ?? {};
const text = message.text?.body ?? body.text ?? body.message ?? '';
const phone = message.from ?? contact.wa_id ?? body.phone ?? '';
const customerName = contact.profile?.name ?? body.customerName ?? 'Cliente WhatsApp';

return [{
  json: {
    rawText: text,
    customerName,
    customerPhone: phone,
    messageType: message.type ?? 'text',
    whatsappMessageId: message.id,
    receivedAt: new Date().toISOString(),
    action: 'create_order',
    type: text.toLowerCase().includes('personalizada') ? 'custom' : 'catalog',
    product: text.toLowerCase().includes('personalizada') ? 'Polera personalizada' : 'Pedido catalogo',
    color: text.match(/color:\s*([^.,]+)/i)?.[1]?.trim(),
    size: text.match(/talla:\s*([^.,]+)/i)?.[1]?.trim(),
    quantity: Number(text.match(/(\d+)\s*prenda/i)?.[1] ?? 1),
    total: Number(text.match(/bs\s*(\d+)/i)?.[1] ?? 0),
    notes: text,
    designDetails: text,
    quoteOption: text.match(/(solo\s+[^.]+|frente\s+[^.]+|espalda\s+[^.]+)/i)?.[1]?.trim()
  }
}];
